window.__QUIZ_DATA__=[{"id":"theory>Geography>2010>THEORY 1>1>a","subject":"Geography","year":"2010","type":"Theory","sub_label":"a","group":"FINAL","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map extracted on a scale of 1:50,000 and answer the following questions:    Calculate the distance \"as the crow flies\" from Agbeyangi to Marafa.     (Leaving the answer in one decimal place)","images":[],"marking_scheme":"Given; Scale = 1 : 20,000  Map distance between Marafa and Abgeyanyi = 20.6cm     \u2234ActualDistance=50,000 x 20.6100,000km    \u2234 The distance \"as the crowflies\" from Agbeyanyi to Maraf is 10.3km","marks":"5","difficulty":"3"},{"id":"theory>Geography>2010>THEORY 1>1>b","subject":"Geography","year":"2010","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"Describe the drainage of the mapped area","images":[],"marking_scheme":"The mapped area is well-drained as it is covered with various networks of various channels (stream). The rivers are at their earthly development stages shown by the dissected highlands. The river pattern is dendritic, maaking the central ridge a major waterished from which rivers take their sources.","marks":"5","difficulty":"2"},{"id":"theory>Geography>2010>THEORY 1>1>c","subject":"Geography","year":"2010","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Explain the relationship between the relief and the road network in the area","images":[],"marking_scheme":"The roads which avoid steep slopes are constructed through passes or sadles and take advantge of the valley floors parallel to the IGPORIN hills. The main road also passes through the major ridges, taking advantage of the lowlands and runs outskirting the ridges.","marks":"5","difficulty":"2"},{"id":"theory>Geography>2010>THEORY 1>1>d","subject":"Geography","year":"2010","type":"Theory","sub_label":"d","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"Identify the drainage of the mapped area","images":[],"marking_scheme":"-Transportational land use  - Educational land use","marks":"5","difficulty":"1"},{"id":"theory>Geography>2010>THEORY 1>2>a","subject":"Geography","year":"2010","type":"Theory","sub_label":"a","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : STATISTICAL MAPS AND DIAGRAMS","question":"The table below shows the quantity of yams in kilogrammes produced by four yam producing states in country x between 2003 and 2006.  State 2003 2004 2005 2006A 200 000 300 000 400 000 500 000B 400 000 400 000 500 000 600 000C 500 000 600 000 700 000 700 000D 600 000 500 000 400 000 300 000    Draw a comparative/group bar graph to represent the statistic.","images":["data:image/png;base64,"],"marking_scheme":"","marks":"10","difficulty":"3"},{"id":"theory>Geography>2010>THEORY 1>2>b","subject":"Geography","year":"2010","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : STATISTICAL MAPS AND DIAGRAMS","question":"The table below shows the quantity of yams in kilogrammes produced by four yam producing states in country x between 2003 and 2006.  State 2003 2004 2005 2006A 200 000 300 000 400 000 500 000B 400 000 400 000 500 000 600 000C 500 000 600 000 700 000 700 000D 600 000 500 000 400 000 300 000  State two advantages of using comparative / group bar graphs in showing statistics","images":[],"marking_scheme":"- It allows for easy computation of items   - It takes for easy comparison of items","marks":"5","difficulty":"2"},{"id":"theory>Geography>2010>THEORY 1>2>c","subject":"Geography","year":"2010","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : STATISTICAL MAPS AND DIAGRAMS","question":"Name one other method that can be used in showing the statistics.","images":[],"marking_scheme":"Composite bar graph","marks":"5","difficulty":"1"},{"id":"theory>Geography>2010>THEORY 1>3>a","subject":"Geography","year":"2010","type":"Theory","sub_label":"a","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"With the aid of a labelled diagrams, describe the instrument used to measure rainfall.","images":["data:image/png;base64,"],"marking_scheme":"The Rain guage consists of a funnel which is either 13-20cm which leads to a glass bottle. The glass bottle is in turn placed in a copper cylinder. The whole apparatus is then placed in a metal container.","marks":"10","difficulty":"2"},{"id":"theory>Geography>2010>THEORY 1>3>b","subject":"Geography","year":"2010","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"Explain how the instruments are used to obtain annual total rain","images":[],"marking_scheme":"The funnel is removed daily, water in the glass jar is emptied into the calibrated measuring cylinder. The reading is taken at eye level and recorded. The readings are summed up for each months and the total rainfall for the twelve months is added and this gives the total annual rainfall.","marks":"5","difficulty":"3"},{"id":"theory>Geography>2010>THEORY 1>3>c","subject":"Geography","year":"2010","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"State any two precautions to be taken in the use of the instruments","images":[],"marking_scheme":"- Rain guage must be at least 25 - 30cm above the ground   - It must be sited in an open space","marks":"5","difficulty":"2"},{"id":"theory>Geography>2010>THEORY 1>4>a","subject":"Geography","year":"2010","type":"Theory","sub_label":"a","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"What is plateau?","images":[],"marking_scheme":"A plateau is an elevated upland with extensive level surface and usually descending steeply to the surrounding lowland","marks":"5","difficulty":"1"},{"id":"theory>Geography>2010>THEORY 1>4>b","subject":"Geography","year":"2010","type":"Theory","sub_label":"b","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"List two types of plateaux","images":[],"marking_scheme":"- Volcanic plateau   - Tectonic plateau","marks":"5","difficulty":"2"},{"id":"theory>Geography>2010>THEORY 1>4>c","subject":"Geography","year":"2010","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Describe the formation of any one type of plateau listed in (b)","images":[],"marking_scheme":"Tectonic plateau:  is formed by earth movement resulting in folding or faulting which causes uplift and depression of some areas. The uplifted area of level land form the techonic plateau E.g. Decan plateau, Columbia snake plateau","marks":"5","difficulty":"3"},{"id":"theory>Geography>2010>THEORY 1>4>d","subject":"Geography","year":"2010","type":"Theory","sub_label":"d","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Highlight three ways in which plateaux are of importance to man","images":[],"marking_scheme":"- Plateaux favour tourism   -They serve as good grazing ground for animals   - They serve as sources of rivers","marks":"5","difficulty":"2"},{"id":"theory>Geography>2010>THEORY 1>5>a","subject":"Geography","year":"2010","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : SOIL","question":"Define the term soil","images":[],"marking_scheme":"Soil is defined as the topmost layer of the earth crust on which plants grow and animals survive","marks":"5","difficulty":"1"},{"id":"theory>Geography>2010>THEORY 1>5>b","subject":"Geography","year":"2010","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : SOIL","question":"Outline three functions of soil","images":[],"marking_scheme":"- It provides habitat for organisms   - It serves as sources of rivers   - It provides raw materials like clay and sand","marks":"5","difficulty":"1"},{"id":"theory>Geography>2010>THEORY 1>5>c","subject":"Geography","year":"2010","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : SOIL","question":"Highlight any two negative effects of man's activities on soil","images":[],"marking_scheme":"- Mining activities destroy top soil   - Loss of ground water through capillary forces","marks":"5","difficulty":"1"},{"id":"theory>Geography>2010>THEORY 1>5>d","subject":"Geography","year":"2010","type":"Theory","sub_label":"d","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL CONSERVATION","question":"Describe any two methods of conserving soil","images":[],"marking_scheme":"- Strip cropping   - Cover cropping","marks":"5","difficulty":"2"},{"id":"theory>Geography>2010>THEORY 1>6>a","subject":"Geography","year":"2010","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Write explanatory notes on the following:    formation of clouds;","images":[],"marking_scheme":"When the ground is heated by the sun resulting in evaporation and eva-transpiration, clouds are formed. After the air is forced to rise to a higher altitude, the cooling of the air which leads to saturation around the hygroscopic nuclei results in coalescence of particles to form clouds.","marks":"10","difficulty":"2"},{"id":"theory>Geography>2010>THEORY 1>6>b","subject":"Geography","year":"2010","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Write explanatory notes on the following:  relief rainfall","images":[],"marking_scheme":"This occurs in mountainous areas. It is common at the coastal area where highlands lie at night angles to the coast. When moist wind comes in contact with the highland, it is forced to rise. The rising air expand at the leeward side and produce the little or no rainfall.","marks":"10","difficulty":"2"},{"id":"theory>Geography>2010>THEORY 1>7>a","subject":"Geography","year":"2010","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL PROBLEMS/ HAZARDS","question":"What is water pollution?","images":[],"marking_scheme":"It is defined as the release or injection of substances into the water bodies i quantities or level that are harmful to man, animal and plants.","marks":"5","difficulty":"1"},{"id":"theory>Geography>2010>THEORY 1>7>b","subject":"Geography","year":"2010","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL PROBLEMS/ HAZARDS","question":"Highlight any three causes of water pollution","images":[],"marking_scheme":"- Oil spillage   - Use of chemical fertilizers   - Discharge of industrial and wastes and household wastes","marks":"5","difficulty":"2"},{"id":"theory>Geography>2010>THEORY 1>7>c","subject":"Geography","year":"2010","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL PROBLEMS/ HAZARDS","question":"Outline three effects of water pollution","images":[],"marking_scheme":"- It leads to high mortality rate of aquatic animals and plants   - It encourages the transmission of water borne diseases   - It pollutes the water and makes it unfit for human usage","marks":"5","difficulty":"2"},{"id":"theory>Geography>2010>THEORY 1>7>d","subject":"Geography","year":"2010","type":"Theory","sub_label":"d","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL CONSERVATION","question":"List any two measures that can be used to control water pollution","images":[],"marking_scheme":"- Provision of public utilities like Incinerator, toilets, etc.   - Proper legislation on the use of waste bodies","marks":"5","difficulty":"2"},{"id":"theory>Geography>2010>THEORY 1>8>a","subject":"Geography","year":"2010","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL PROBLEMS/ HAZARDS","question":"Write explanatory notes on drought under the following:    causes","images":[],"marking_scheme":"Draught is caused by the complete absence of rainfall, changes in weather and climate and daily conditions of high temperature and pressure. It is also caused by high rate of evaporation and evaporation, low cloud cover, and low humidity.","marks":"10","difficulty":"3"},{"id":"theory>Geography>2010>THEORY 1>8>b","subject":"Geography","year":"2010","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL PROBLEMS/ HAZARDS","question":"Write explanatory notes on drought under the following:  effects","images":[],"marking_scheme":"Drought leads to famine i.e. lack of food in a land, crop failure, forced migration, malnutrition, desertification, etc.","marks":"5","difficulty":"2"},{"id":"theory>Geography>2010>THEORY 1>8>c","subject":"Geography","year":"2010","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL CONSERVATION","question":"Write explanatory notes on drought under the following:  control","images":[],"marking_scheme":"Control of Drought   Drought can be controlled by construction of irrigation dams, planting cover crops environmental education, legislation against deforestation and bush burning.","marks":"5","difficulty":"2"},{"id":"theory>Geography>2010>THEORY 2>1>a","subject":"Geography","year":"2010","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Explain the term rural settlement","images":[],"marking_scheme":"Rural Settlement is a small settlement consisting of a few people. E.g village, hamlet, farmstead, homestead, etc. It encourages mainly in primary activities like fishing, lumbering, etc.","marks":"10","difficulty":"1"},{"id":"theory>Geography>2010>THEORY 2>1>b","subject":"Geography","year":"2010","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Describe any two types of rural settlement","images":[],"marking_scheme":"Types of Rural Settlements    -  Village:  This is made up of hamlets, which contain homestead. It may be dispersed or nucleated or both and may also been linearly or dispersed in shape. The people there engage in mainly primary activities.   -  Hamlet:  It is made up of dispersed nuclear or linear homesteads which may have shops, schools with hundreds of people advanced countries but are inaccessible in developing countries.   -  Farmstead:  It compromises two or more homesteads which are usually dispersed. They are separated by farmlands and occupied by about fifty persons.","marks":"5","difficulty":"2"},{"id":"theory>Geography>2010>THEORY 2>1>c","subject":"Geography","year":"2010","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Outline five differences between rural and urban settlements","images":[],"marking_scheme":"Differences between Urban and Rural Settlements   Rural Settlements Urban settlements1. They are broken into homesteads; farmsteads; hamlets and villages They are graded into conurbations; megalopolis millionaira city; agglomeration etc. 2. They are generally smaller in sizes than urban settlements They are larger in size than the rural settlements3. They are less prone to pollution They are more prone to pollution than rural settlements4. They have less-developed layouts than urban settlements They has well developed or planned layouts5. They are less populated than the urban areas They are well developed or planned layouts","marks":"5","difficulty":"2"},{"id":"theory>Geography>2010>THEORY 2>2>a>i","subject":"Geography","year":"2010","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"Name any three commodities of world trade","images":[],"marking_scheme":"- Mineral Resources e.g Gold, Tin, etc.   - Food items, e.g cocoa, rice, wheat, etc.   - Agricultural raw materials e.g. cotton, rubber, etc.","marks":"5","difficulty":"1"},{"id":"theory>Geography>2010>THEORY 2>2>a>ii","subject":"Geography","year":"2010","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"Identify three seas routes in the world","images":[],"marking_scheme":"- South pacific sea route   - North Atlantic sea route  - Panema sea routes","marks":"5","difficulty":"1"},{"id":"theory>Geography>2010>THEORY 2>2>b","subject":"Geography","year":"2010","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"Explain any four conditions that promote trade among countries.","images":[],"marking_scheme":"- Demand for products   - Difference in weather and climate   - Transportation facilities","marks":"5","difficulty":"2"},{"id":"theory>Geography>2010>THEORY 2>2>c","subject":"Geography","year":"2010","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"Outline any three reasons for the low volume of trade among African countries.","images":[],"marking_scheme":"- Product similarities   - Low level of finance/resources  - Trade tariffs/barriers","marks":"5","difficulty":"2"},{"id":"theory>Geography>2010>THEORY 2>3>a","subject":"Geography","year":"2010","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : INDUSTRY","question":"Describe any three features of local craft industry in Nigeria","images":[],"marking_scheme":"- Irregular working hour   - Irregular income is made   - All year round employment","marks":"10","difficulty":"2"},{"id":"theory>Geography>2010>THEORY 2>3>b","subject":"Geography","year":"2010","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : INDUSTRY","question":"Outline any four factors affecting the location of manufacturing industries in Nigeria","images":[],"marking_scheme":"- Nearness to markets   - Nearness to source of raw materials   - Availability of capital and power supply   - Government policy","marks":"5","difficulty":"2"},{"id":"theory>Geography>2010>THEORY 2>3>c","subject":"Geography","year":"2010","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : INDUSTRY","question":"Highlight any three ways in which industries have contributed to the economy of Nigeria","images":[],"marking_scheme":"- They serve as source of foreign exchange   - They control inflation through mass production   - They improve the standard of living of the people.","marks":"5","difficulty":"2"},{"id":"theory>Geography>2010>THEORY 2>4>a","subject":"Geography","year":"2010","type":"Theory","sub_label":"a","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Draw any outline map of Nigeria   On it show and name one area important for the mining of  (i) coal (ii) limestone; (iii) crude oil (iv) one important town in (a)(iii)","images":["data:image/png;base64,"],"marking_scheme":"","marks":"10","difficulty":"3"},{"id":"theory>Geography>2010>THEORY 2>4>b","subject":"Geography","year":"2010","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : INDUSTRY","question":"Describe three problems associated with the exploration of minerals in Nigeria","images":[],"marking_scheme":"- Inadequate skilled labour   - Inadequate capital   - Environmental deterioration","marks":"5","difficulty":"2"},{"id":"theory>Geography>2010>THEORY 2>4>c","subject":"Geography","year":"2010","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : INDUSTRY","question":"Highlight three contributions of mineral to the economic development of Nigeria","images":[],"marking_scheme":"- Provision of employment   - Improved standard of living   - Provision of essential goods.","marks":"5","difficulty":"2"},{"id":"theory>Geography>2010>THEORY 2>5>a>i","subject":"Geography","year":"2010","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"What is mineral trade?","images":[],"marking_scheme":"Internal trade means the buying and selling or exchange of goods and services within the country.","marks":"5","difficulty":"1"},{"id":"theory>Geography>2010>THEORY 2>5>a>ii","subject":"Geography","year":"2010","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : TRADE","question":"Name four commodities involved in internal trade in Nigeria","images":[],"marking_scheme":"- Cement   - Textiles   - Food items   - Motor vehicles","marks":"5","difficulty":"2"},{"id":"theory>Geography>2010>THEORY 2>5>b","subject":"Geography","year":"2010","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : TRADE","question":"Highlight four factors that encourage internal trade in Nigeria","images":[],"marking_scheme":"- Good transportation network   - Climate difference between regions   - Common currency   - Bank loans and credits","marks":"5","difficulty":"2"},{"id":"theory>Geography>2010>THEORY 2>5>c","subject":"Geography","year":"2010","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : TRADE","question":"Outline three problems limiting internal trade in Nigeria","images":[],"marking_scheme":"- Similarity of products in the market   - High rate of rural settlements   - Smuggling of products","marks":"5","difficulty":"2"},{"id":"theory>Geography>2010>THEORY 2>6>a","subject":"Geography","year":"2010","type":"Theory","sub_label":"a","group":"","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"Draw a sketch map of Africa. On it show and name the following:   (i) cocoa belt; (ii) groundnut belt; (iii) one town on the groundnut belt","images":["data:image/png;base64,"],"marking_scheme":"","marks":"10","difficulty":"3"},{"id":"theory>Geography>2010>THEORY 2>6>b","subject":"Geography","year":"2010","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Outline three physical conditions for the production of groundnut in Nigeria","images":[],"marking_scheme":"- Wide plains of the North for easy cultivation   - Loose sandy or loamy soil for planting and harvesting   - Moderate rainfall of up to 100cm annually","marks":"5","difficulty":"2"},{"id":"theory>Geography>2010>THEORY 2>6>c","subject":"Geography","year":"2010","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"In what four ways has groundnut production contributed to the economy of Nigeria?","images":[],"marking_scheme":"- Provision of animal foods   - Industrial raw materials   - Employment   - Development of transport network","marks":"5","difficulty":"2"},{"id":"theory>Geography>2010>THEORY 2>7>a","subject":"Geography","year":"2010","type":"Theory","sub_label":"a","group":"","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"Draw an outline map of Africa. On it show and name the following:  (i) the Equatorial rain forest; (ii) the Tropical grassland; (iii) one town in each of the areas in (a)(i) and (a)(ii)","images":["data:image/png;base64,"],"marking_scheme":"","marks":"10","difficulty":"3"},{"id":"theory>Geography>2010>THEORY 2>7>b","subject":"Geography","year":"2010","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : VEGETATION","question":"Outline three characteristics of the Equatorial rainforest vegetation.","images":[],"marking_scheme":"- Trees form continuous canopy in the upper layer   - Layered arrangement of vegetation cover   - Presence of climbers and lianas","marks":"5","difficulty":"2"},{"id":"theory>Geography>2010>THEORY 2>7>c","subject":"Geography","year":"2010","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : VEGETATION","question":"In what three ways is the Tropical rainforest of economical importance?","images":[],"marking_scheme":"- Leaves, roots and banks are used for medicinal purposes   - Fruits and seeds serve as food   - Trees serve as source of timber","marks":"5","difficulty":"2"},{"id":"theory>Geography>2010>THEORY 2>8>a","subject":"Geography","year":"2010","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF AFRICA : SELECTED TOPICS","question":"Name any four irrigation areas in the Nile Valley","images":[],"marking_scheme":"- Semar in Sudan   - Kenena in Sudan   - Middle Nile valley in Sudan   - Lake shores","marks":"10","difficulty":"2"},{"id":"theory>Geography>2010>THEORY 2>8>b","subject":"Geography","year":"2010","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF AFRICA : SELECTED TOPICS","question":"Describe the perennial method of irrigation in the Nile Valley","images":[],"marking_scheme":"Modern methods are mostly used in the Nile volley Dams which are built across the Nile hold back some of the Nile water during the floods. The water stored behind the dams is released especially when the river level is low. By releasing the water that is allowed to flow by gravity to farming takes place through out the year.","marks":"5","difficulty":"3"},{"id":"theory>Geography>2010>THEORY 2>8>c","subject":"Geography","year":"2010","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF AFRICA : SELECTED TOPICS","question":"Explain any four problems created by irrigation in the Nile valley","images":[],"marking_scheme":"- It uses up the water which could have been used for other demands   - It encourages growth of water weeds   - It leads to decrease in amount of fresh water for the fishing Industry in Egypt.   - It has brought about reduction in segments of the lower Nile, leading to the flooding of over 40,000 hectares of fertile farm lands due to the decrease in the rate at which sand banks are being built in the delta.","marks":"5","difficulty":"3"},{"id":"theory>Geography>2010>THEORY 2>9>a","subject":"Geography","year":"2010","type":"Theory","sub_label":"a","group":"","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"Draw a sketch map of Africa. On the map show and name:  (i) two oil producing areas (ii) one town in each of the areas in (a)(i) above","images":["data:image/png;base64,"],"marking_scheme":"","marks":"10","difficulty":"3"},{"id":"theory>Geography>2010>THEORY 2>9>b","subject":"Geography","year":"2010","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF AFRICA : SELECTED TOPICS","question":"Highlight any three contributions of oil to the economic development of one of the areas shown in   (a)(ii)","images":[],"marking_scheme":"- Improved standard of living   - Skill acquisition   - Provision of raw materials for Industries","marks":"5","difficulty":"2"},{"id":"theory>Geography>2010>THEORY 2>9>c","subject":"Geography","year":"2010","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : INDUSTRY","question":"Describe any three problems affecting the mining of petroleum in one of the three area shown in (a)(i)","images":[],"marking_scheme":"- Poor transport network   - Inadequate capital to efficiently explain the mineral   - Poor management","marks":"5","difficulty":"2"}];